"""Tool-calling agent loop.

The model decides which tool to call next; we dispatch, append the result to
the message history, and re-prompt. Loop exits when the model calls
``final_answer`` or the step budget is exhausted.
"""

from __future__ import annotations

import json
import re
import sys
from dataclasses import dataclass, field
from typing import Any

from openai import OpenAI

from text2sql_agent.config import Settings
from text2sql_agent.schema import schema_text
from text2sql_agent.tools import TOOLS_SCHEMA, dispatch


SYSTEM_PROMPT = """Ты — ассистент text2sql для Oracle XE над таблицей `client_product`.

Твоя задача: на NL-вопрос пользователя дать конкретный ответ с цифрами из БД.

Алгоритм (модель сама выбирает шаги через tool calls):
1. При необходимости — `inspect_schema` для деталей по полям и примерам SQL.
2. Сформируй корректный Oracle SQL (SELECT/WITH). Используй DATE 'YYYY-MM-DD' для дат,
   FETCH FIRST N ROWS ONLY вместо LIMIT, ORDER BY для top-N запросов.
3. Запусти SQL через `execute_sql`.
4. Проверь результат через `validate_result` с разумными `expectations`
   (min_rows, non_null_columns для ключевых колонок, numeric_ranges).
5. Если что-то не так — поправь SQL и повтори (не более 2-3 раз).
6. Заверши `final_answer` — короткий русский ответ с конкретными числами,
   единицами (рубли / шт. / клиенты) и одной строкой интерпретации.

Правила SQL:
- ТОЛЬКО SELECT/WITH; никаких INSERT/UPDATE/DELETE/DDL.
- Не суммируй "итоговые" поля с их компонентами (PNL_SUM с PL_CA, FX_VOLUME_RUB с FX_EUR_VOLUME_RUB и т.п.) — см. метаданные.
- Поля с агрегацией AVG между месяцами (балансы) — если суммируешь по месяцам, это даёт «сумму средних», что обычно не то, что хочет пользователь. Для остатков на дату/период бери AVG по месяцам или MAX(MONTH_DT).
- Не выдумывай поля — если поля нет, скажи об этом в final_answer.
- Текстовые сравнения по именам организаций используй с UPPER(...) LIKE '%...%'.

Правила ответа:
- Числа в рублях форматируй с разделителями разрядов и единицами (млн ₽, млрд ₽ — где уместно).
- Если результат пустой — честно скажи, что данных нет, не выдумывай.
- Не вставляй сырой SQL в final_answer; только конечные цифры и смысл.
"""


@dataclass
class AgentTrace:
    """Captures everything that happened during a run, for tests/debug."""

    steps: list[dict[str, Any]] = field(default_factory=list)
    final_text: str = ""
    final_supporting: dict[str, Any] = field(default_factory=dict)


@dataclass
class Text2SqlAgent:
    settings: Settings
    max_steps: int = 8
    log_stream: Any = sys.stderr

    def _client(self) -> OpenAI:
        return OpenAI(base_url=self.settings.api_url, api_key=self.settings.api_key)

    def _log(self, msg: str) -> None:
        if self.log_stream is not None:
            print(msg, file=self.log_stream, flush=True)

    def _data_range_note(self) -> str:
        """Probe MIN/MAX MONTH_DT once; tells the model the *real* date range so
        it can warn about partial periods (PREMORTEM #3). Failures are swallowed
        — without a range note the agent still works, just without that hint.
        """
        try:
            from text2sql_agent.db import run_query

            r = run_query(
                "SELECT MIN(MONTH_DT) AS MIN_M, MAX(MONTH_DT) AS MAX_M FROM client_product",
                self.settings,
            )
            if r["rows"] and r["rows"][0][0]:
                lo, hi = r["rows"][0]
                return (
                    f"Реальный диапазон MONTH_DT в таблице: {lo} .. {hi}. "
                    "Если вопрос пользователя выходит за этот диапазон — явно "
                    "укажи это в final_answer (например, «данные только до …»). "
                    "Не давай ответ за весь год, если данные покрывают лишь его часть."
                )
        except Exception:  # noqa: BLE001 — best-effort hint
            pass
        return ""

    def run(self, question: str) -> AgentTrace:
        client = self._client()
        trace = AgentTrace()
        system_content = SYSTEM_PROMPT + "\n\n# Схема данных\n\n" + schema_text()
        range_note = self._data_range_note()
        if range_note:
            system_content += "\n\n# Диапазон данных\n\n" + range_note
        messages: list[dict[str, Any]] = [
            {"role": "system", "content": system_content},
            {"role": "user", "content": question},
        ]

        for step in range(self.max_steps):
            self._log(f"[agent] step {step + 1}/{self.max_steps}: requesting completion")
            response = client.chat.completions.create(
                model=self.settings.sql_model,
                messages=messages,
                tools=TOOLS_SCHEMA,
                tool_choice="auto",
                temperature=0.1,
            )
            msg = response.choices[0].message
            finish = response.choices[0].finish_reason

            content = _strip_think(msg.content or "")
            messages.append(
                {
                    "role": "assistant",
                    "content": content,
                    "tool_calls": [
                        {
                            "id": tc.id,
                            "type": "function",
                            "function": {
                                "name": tc.function.name,
                                "arguments": tc.function.arguments,
                            },
                        }
                        for tc in (msg.tool_calls or [])
                    ]
                    or None,
                }
            )

            if not msg.tool_calls:
                # Model produced free text (or nothing) instead of a tool call.
                if content.strip():
                    self._log(
                        f"[agent] step {step + 1}: plain text (finish={finish}); using as final answer."
                    )
                    trace.final_text = content.strip()
                    trace.steps.append({"step": step + 1, "kind": "plain_text", "content": content})
                    return trace
                self._log(
                    f"[agent] step {step + 1}: empty content + no tool_calls (finish={finish}); nudging."
                )
                messages.append(
                    {
                        "role": "user",
                        "content": (
                            "Ты вернул пустое сообщение без tool_call. Вызови `final_answer` "
                            "сейчас с короткой формулировкой ответа на основе уже полученных "
                            "данных. Если данных недостаточно — вызови `execute_sql` сначала."
                        ),
                    }
                )
                trace.steps.append({"step": step + 1, "kind": "empty_nudge"})
                continue

            for tc in msg.tool_calls:
                name = tc.function.name
                try:
                    raw_args = tc.function.arguments or "{}"
                    args = json.loads(raw_args) if isinstance(raw_args, str) else raw_args
                except json.JSONDecodeError as exc:
                    args = {}
                    result: Any = {"error": f"invalid JSON arguments: {exc}"}
                else:
                    self._log(f"[agent] step {step + 1}: tool={name} args={_preview(args)}")
                    try:
                        result = dispatch(name, args, self.settings)
                    except Exception as exc:  # noqa: BLE001 — surface to model
                        result = {"error": f"{type(exc).__name__}: {exc}"}

                trace.steps.append(
                    {"step": step + 1, "tool": name, "args": args, "result": _summarise(result)}
                )

                if name == "final_answer":
                    text = (result or {}).get("text", "") or ""
                    if not text.strip():
                        # Empty payload — treat as the same problem as empty content
                        # and nudge once instead of silently returning blank stdout.
                        self._log(
                            f"[agent] step {step + 1}: final_answer with empty text; nudging."
                        )
                        messages.append(
                            {
                                "role": "tool",
                                "tool_call_id": tc.id,
                                "name": name,
                                "content": json.dumps(
                                    {"error": "final_answer must include non-empty `text`"},
                                    ensure_ascii=False,
                                ),
                            }
                        )
                        trace.steps.append({"step": step + 1, "kind": "empty_final_answer"})
                        continue
                    trace.final_text = text
                    trace.final_supporting = (result or {}).get("supporting_data", {}) or {}
                    return trace

                messages.append(
                    {
                        "role": "tool",
                        "tool_call_id": tc.id,
                        "name": name,
                        "content": json.dumps(
                            _clip_for_history(result), ensure_ascii=False, default=str
                        ),
                    }
                )

        self._log("[agent] step budget exhausted without final_answer")
        trace.final_text = (
            "Не удалось получить финальный ответ за отведённый бюджет шагов. "
            "Попробуй переформулировать вопрос."
        )
        return trace


def answer(question: str, settings: Settings | None = None) -> AgentTrace:
    """Convenience: run one question end-to-end."""
    return Text2SqlAgent(settings=settings or Settings.from_env()).run(question)


_THINK_RE = re.compile(r"<think>.*?</think>", re.DOTALL | re.IGNORECASE)


def _strip_think(text: str) -> str:
    """Qwen Instruct prepends <think>…</think> — never useful downstream."""
    return _THINK_RE.sub("", text).strip()


def _preview(value: Any, limit: int = 200) -> str:
    s = json.dumps(value, ensure_ascii=False, default=str)
    return s if len(s) <= limit else s[: limit - 3] + "..."


def _summarise(result: Any) -> Any:
    """Trim large SQL results before storing in the trace."""
    if isinstance(result, dict) and "rows" in result and isinstance(result["rows"], list):
        rows = result["rows"]
        return {
            "columns": result.get("columns"),
            "row_count": len(rows),
            "truncated": result.get("truncated", False),
            "preview": rows[:5],
        }
    return result


_HISTORY_ROW_LIMIT = 30


def _clip_for_history(result: Any) -> Any:
    """Trim execute_sql results before re-injecting them into the LLM message
    history. Without this, a 100-200 row JSON payload accumulates on every turn
    and pushes Qwen into empty-`<think>` loops (observed in EVIDENCE Run 6).

    Aggregate queries (1 row) pass through untouched; only detail queries are
    clipped, with explicit `row_count` and `clipped_to` fields so the model
    knows it didn't get the full result.
    """
    if not isinstance(result, dict):
        return result
    rows = result.get("rows")
    if not isinstance(rows, list) or len(rows) <= _HISTORY_ROW_LIMIT:
        return result
    return {
        **{k: v for k, v in result.items() if k != "rows"},
        "rows": rows[:_HISTORY_ROW_LIMIT],
        "row_count": len(rows),
        "clipped_to": _HISTORY_ROW_LIMIT,
        "clipped_note": (
            f"Возвращено {len(rows)} строк; в этом сообщении показаны первые "
            f"{_HISTORY_ROW_LIMIT}. Для агрегации используй сам SQL (GROUP BY / "
            f"SUM / COUNT), а не сырые строки."
        ),
    }

"""Tool implementations + OpenAI tool schemas.

Each tool is a small Python function and a JSON schema dict. The agent loop
hands these to the model and dispatches based on the model's tool_calls.
"""

from __future__ import annotations

from typing import Any

from text2sql_agent.config import Settings
from text2sql_agent.db import SqlExecutionError, run_query
from text2sql_agent.schema import describe_table


# ----------------------------------------------------------------------------
# Tool implementations
# ----------------------------------------------------------------------------


def inspect_schema(table: str = "client_product") -> dict[str, Any]:
    """Return the table description + field metadata + SQL examples."""
    try:
        return describe_table(table)
    except ValueError as exc:
        return {"error": str(exc)}


def execute_sql(sql: str, settings: Settings) -> dict[str, Any]:
    """Run a SELECT and return rows (truncated to 200)."""
    try:
        return run_query(sql, settings)
    except SqlExecutionError as exc:
        return {"error": str(exc)}


def validate_result(
    result: dict[str, Any],
    expectations: dict[str, Any] | None = None,
) -> dict[str, Any]:
    """Sanity-check a query result.

    Checks:
      - result was actually returned (no `error` key);
      - row count vs min/max expectations;
      - non-null key columns (by name);
      - numeric range bounds per column.

    Returns ``{"ok": bool, "issues": [str], "warnings": [str]}``.
    """
    issues: list[str] = []
    warnings: list[str] = []
    expectations = expectations or {}

    if not isinstance(result, dict):
        return {"ok": False, "issues": [f"result is not a dict: {type(result).__name__}"], "warnings": []}
    if "error" in result:
        return {"ok": False, "issues": [f"SQL error: {result['error']}"], "warnings": []}

    rows = result.get("rows", [])
    columns: list[str] = result.get("columns", []) or []
    n = len(rows)

    if (min_rows := expectations.get("min_rows")) is not None and n < int(min_rows):
        issues.append(f"row_count={n} < min_rows={min_rows}")
    if (max_rows := expectations.get("max_rows")) is not None and n > int(max_rows):
        issues.append(f"row_count={n} > max_rows={max_rows}")

    if n == 0:
        warnings.append("Запрос вернул 0 строк — проверь фильтры (даты, сегменты, имена).")

    nn_cols = expectations.get("non_null_columns", []) or []
    for col in nn_cols:
        if col not in columns:
            warnings.append(f"non_null_columns: колонка {col!r} отсутствует в результате")
            continue
        idx = columns.index(col)
        nulls = sum(1 for r in rows if r[idx] is None)
        if nulls:
            issues.append(f"колонка {col!r} содержит {nulls} NULL значений (ожидалось 0)")

    ranges = expectations.get("numeric_ranges", {}) or {}
    for col, bounds in ranges.items():
        if col not in columns:
            warnings.append(f"numeric_ranges: колонка {col!r} отсутствует в результате")
            continue
        idx = columns.index(col)
        lo = bounds.get("min")
        hi = bounds.get("max")
        for ri, r in enumerate(rows):
            v = r[idx]
            if v is None or not isinstance(v, (int, float)):
                continue
            if lo is not None and v < lo:
                issues.append(f"row {ri}: {col}={v} < min={lo}")
                break
            if hi is not None and v > hi:
                issues.append(f"row {ri}: {col}={v} > max={hi}")
                break

    if result.get("truncated"):
        warnings.append("Результат обрезан до 200 строк — для агрегатов это обычно нормально, для деталей нужно сузить выборку.")

    return {"ok": not issues, "issues": issues, "warnings": warnings}


def final_answer(text: str, supporting_data: dict[str, Any] | None = None) -> dict[str, Any]:
    """Marker tool: signals the agent loop to stop and return ``text`` to the user."""
    return {"text": text, "supporting_data": supporting_data or {}}


