def dispatch(name: str, arguments: dict[str, Any], settings: Settings) -> Any:
    """Execute a tool by name. Raises KeyError for unknown tools."""
    if name == "inspect_schema":
        return inspect_schema(arguments.get("table", "client_product"))
    if name == "execute_sql":
        sql = arguments.get("sql", "")
        return execute_sql(sql, settings)
    if name == "validate_result":
        return validate_result(arguments.get("result", {}), arguments.get("expectations"))
    if name == "final_answer":
        return final_answer(arguments.get("text", ""), arguments.get("supporting_data"))
    raise KeyError(f"Unknown tool: {name}")

