def get_table_metadata(table_name: str = "client_product") -> dict[str, Any]:
    """Возвращает метаданные указанной таблицы."""
    if table_name == "client_product":
        return ALL_CLI_METADATA
    raise ValueError(f"Таблица {table_name} не найдена в метаданных")


def get_sql_examples(table_name: str = "client_product") -> list[dict[str, str]]:
    """Возвращает примеры SQL запросов для таблицы."""
    metadata = get_table_metadata(table_name)
    examples: list[dict[str, str]] = metadata.get("sql_examples", [])
    return examples

"""Unit tests for the four tool functions."""

from __future__ import annotations

from text2sql_agent.tools import (
    TOOLS_SCHEMA,
    final_answer,
    inspect_schema,
    validate_result,
)


class TestInspectSchema:
    def test_returns_client_product_metadata(self):
        d = inspect_schema("client_product")
        assert d["table_name"] == "client_product"
        assert "MONTH_DT" in d["fields"]
        assert d["fields"]["MONTH_DT"]["is_key"] is True
        assert any("FX" in f for f in d["fields"])
        assert isinstance(d["sql_examples"], list)
        assert d["sql_examples"]

    def test_unknown_table_returns_error(self):
        d = inspect_schema("nonexistent_table")
        assert "error" in d


class TestValidateResult:
    def _row_result(self, columns, rows, **extra):
        return {"columns": columns, "rows": rows, "row_count": len(rows), **extra}

    def test_ok_when_no_expectations(self):
        r = self._row_result(["C"], [[42]])
        assert validate_result(r) == {"ok": True, "issues": [], "warnings": []}

    def test_min_rows_violation_reported(self):
        r = self._row_result(["C"], [])
        v = validate_result(r, {"min_rows": 1})
        assert v["ok"] is False
        assert any("min_rows" in i for i in v["issues"])

    def test_zero_rows_warning(self):
        r = self._row_result(["C"], [])
        v = validate_result(r)
        assert v["ok"] is True
        assert any("0 строк" in w for w in v["warnings"])

    def test_non_null_violation(self):
        r = self._row_result(["X", "Y"], [[1, None], [2, 3]])
        v = validate_result(r, {"non_null_columns": ["Y"]})
        assert v["ok"] is False
        assert any("Y" in i and "NULL" in i for i in v["issues"])

    def test_numeric_range_violation(self):
        r = self._row_result(["S"], [[42], [1_000_000_000_000_000]])
        v = validate_result(r, {"numeric_ranges": {"S": {"max": 1_000_000}}})
        assert v["ok"] is False
        assert any("> max" in i for i in v["issues"])

    def test_error_in_result_is_not_ok(self):
        v = validate_result({"error": "ORA-00942: table not found"})
        assert v["ok"] is False
        assert any("SQL error" in i for i in v["issues"])

    def test_truncated_emits_warning(self):
        r = self._row_result(["C"], [[1]], truncated=True)
        v = validate_result(r)
        assert any("обрезан" in w for w in v["warnings"])


class TestFinalAnswer:
    def test_packs_text_and_data(self):
        r = final_answer("103 клиента.", {"clients": 103})
        assert r["text"] == "103 клиента."
        assert r["supporting_data"] == {"clients": 103}


class TestToolsSchema:
    def test_all_required_tools_defined(self):
        names = {t["function"]["name"] for t in TOOLS_SCHEMA}
        assert names == {"inspect_schema", "execute_sql", "validate_result", "final_answer"}

    def test_each_tool_has_parameters_schema(self):
        for t in TOOLS_SCHEMA:
            params = t["function"]["parameters"]
            assert params["type"] == "object"
            assert "properties" in params

"""Test fixtures: live Oracle / Ollama probes that skip when unavailable.

We intentionally do NOT mock Oracle (per `.claude/rules/testing.md`): mocked
DB tests passed historically while prod migrations failed. Integration tests
require a live container; they self-skip otherwise.
"""

from __future__ import annotations

import socket
import urllib.error
import urllib.request
from urllib.parse import urlparse

import pytest


def _tcp_open(host: str, port: int, timeout: float = 1.0) -> bool:
    try:
        with socket.create_connection((host, port), timeout=timeout):
            return True
    except OSError:
        return False


def _http_ok(url: str, timeout: float = 2.0) -> bool:
    try:
        with urllib.request.urlopen(url, timeout=timeout) as r:
            return 200 <= r.status < 500
